import React, { useState, useEffect } from 'react';
import { useTheme } from '../context/ThemeContext';
import { FaPrint, FaTrash, FaFileInvoice, FaShieldAlt, FaMapMarkerAlt, FaClock, FaChevronRight, FaBars, FaBell, FaDownload, FaCheckCircle, FaQrcode } from 'react-icons/fa';
import Logo from '../components/Logo';
import Sidebar from '../components/Sidebar';
import MobileSOSReports from './MobileSOSReports';
import './Dashboard.css';

const SOSReports = () => {
  const { theme } = useTheme();
  const dark = theme === 'dark';
  const [reports, setReports] = useState([]);
  const [selectedReport, setSelectedReport] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);

  useEffect(() => {
    const checkRes = () => setIsMobile(window.innerWidth <= 768);
    window.addEventListener('resize', checkRes);
    return () => window.removeEventListener('resize', checkRes);
  }, []);

  const loggedInUser = JSON.parse(localStorage.getItem('trinetra_user') || '{}');

  useEffect(() => {
    setTimeout(() => {
      const saved = JSON.parse(localStorage.getItem('trinetra_sos_reports') || '[]');
      setReports(saved.reverse());
      setLoading(false);
    }, 800);
  }, []);

  const deleteReport = (id) => {
    if (window.confirm("Are you sure you want to delete this evidence report?")) {
      const updated = reports.filter(r => r.id !== id);
      setReports(updated);
      localStorage.setItem('trinetra_sos_reports', JSON.stringify(updated.reverse()));
      if (selectedReport?.id === id) setSelectedReport(null);
    }
  };

  const handleDownload = () => {
    if (!selectedReport) return;

    // STEP: Paste your logo's Base64 string between the quotes below
    const logoBase64 = "data:image/png;base64,"

    const fullHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <title>TRINETRA_AUDIT_${selectedReport.id}</title>
          <style>
            @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;700;900&display=swap');
            body { font-family: 'Inter', sans-serif; background: #e2e8f0; padding: 50px; color: #1a202c; margin: 0; }
            .a4-container { background: #ffffff; width: 210mm; min-height: 297mm; margin: 0 auto; padding: 25mm; box-sizing: border-box; position: relative; border: 8px double #1a202c; box-shadow: 0 40px 80px rgba(0,0,0,0.15); }
            
            .security-grid { position: absolute; inset: 0; opacity: 0.03; background-image: radial-gradient(#000 0.5px, transparent 0.5px); background-size: 10px 10px; pointer-events: none; }
            
            .header { display: flex; justify-content: space-between; border-bottom: 3px solid #1a202c; padding-bottom: 25px; margin-bottom: 40px; align-items: center; }
            .brand-box { display: flex; align-items: center; gap: 15px; }
            
            .case-badge { background: #1a202c; color: #fff; padding: 15px 25px; border-radius: 4px; text-align: right; }
            .case-badge label { display: block; font-size: 10px; opacity: 0.7; font-weight: 700; }
            .case-badge strong { font-size: 20px; font-weight: 900; letter-spacing: 1px; }

            .title-section { text-align: center; margin-bottom: 50px; }
            .title-section h1 { font-size: 36px; margin: 0; font-weight: 900; text-transform: uppercase; letter-spacing: -1px; }
            .title-section p { font-size: 12px; font-weight: 700; color: #4a5568; letter-spacing: 4px; margin-top: 5px; }

            .section { margin-bottom: 40px; }
            .section-title { font-size: 12px; font-weight: 900; border-bottom: 1px solid #cbd5e0; padding-bottom: 10px; margin-bottom: 20px; letter-spacing: 2px; color: #1a202c; }
            
            .data-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 30px; }
            .data-field label { display: block; font-size: 9px; font-weight: 900; color: #718096; margin-bottom: 5px; text-transform: uppercase; }
            .data-field span { font-size: 16px; font-weight: 700; color: #2d3748; }

            .evidence-box { background: #f7fafc; padding: 25px; border-radius: 8px; border: 1px solid #e2e8f0; margin-top: 15px; position: relative; }
            .stamp { position: absolute; right: 20px; top: 50%; transform: translateY(-50%) rotate(-15deg); border: 4px solid #c53030; color: #c53030; padding: 10px 20px; font-size: 24px; font-weight: 900; border-radius: 8px; opacity: 0.2; pointer-events: none; }

            .footer { margin-top: auto; border-top: 2px solid #edf2f7; padding-top: 40px; display: flex; justify-content: space-between; align-items: flex-end; }
            
            .watermark { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%) rotate(-45deg); font-size: 150px; font-weight: 900; color: rgba(0,0,0,0.02); pointer-events: none; white-space: nowrap; }
          </style>
        </head>
        <body>
          <div class="a4-container">
            <div class="security-grid"></div>
            <div class="watermark">TRINETRA</div>
            
            <div class="header">
              <div class="brand-box">
                <!-- User's Manual Logo -->
                <img src="${logoBase64}" alt="TRINETRA" style="height: 120px; width: auto; object-fit: contain;" onerror="this.style.display='none'"/>
                <div>
                    <div style="font-size: 42px; font-weight: 900; color: #1a202c; letter-spacing: -1px; line-height: 1;">TRINETRA</div>
                    <div style="font-size: 13px; font-weight: 700; color: #B8860B; letter-spacing: 3px; text-transform: uppercase; margin-top: 4px;">Eye of Protection</div>
                </div>
              </div>
              <div class="case-badge">
                <label>INCIDENT AUDIT ID</label>
                <strong>#${selectedReport.id.toString().slice(-8).toUpperCase()}</strong>
              </div>
            </div>

            <div class="title-section">
              <h1>Incident Evidence Log</h1>
              <p>Department of Global Security & Emergency Response</p>
            </div>

            <div class="section">
              <div class="section-title">I. Victim & Subject Identification</div>
              <div class="data-grid">
                <div class="data-field"><label>Full Name</label><span>${selectedReport.userName || 'Verified User'}</span></div>
                <div class="data-field"><label>Security Level</label><span style="color: #c53030;">PRIORITY ALPHA</span></div>
                <div class="data-field"><label>System Status</label><span>ENCRYPTED_LOG_SECURE</span></div>
                <div class="data-field"><label>Audit Version</label><span>v2.0.4 - FORENSIC</span></div>
              </div>
            </div>

            <div class="section">
              <div class="section-title">II. Chronological Incident Telemetry</div>
              <div class="data-grid">
                <div class="data-field"><label>Activation Timestamp</label><span>${new Date(selectedReport.timestamp).toLocaleString()}</span></div>
                <div class="data-field" style="position: relative;">
                  <label>Incident Location</label>
                  <span>${selectedReport.locationName}</span>
                  <div class="stamp" style="font-size: 16px; padding: 5px 10px; border-width: 2px; top: 10px; right: 0;">VERIFIED</div>
                </div>
              </div>
            </div>

            <div class="section">
              <div class="section-title">III. Distress Communication Audit</div>
              <div style="background: #1a202c; color: white; padding: 20px; border-radius: 4px; font-family: monospace; font-size: 14px; line-height: 1.6;">
                <span style="color: #f4b400;">[SYSTEM_LOG]</span> SOS Triggered via ${selectedReport.message.includes('Dashboard') ? 'Command Center' : 'Direct Mobile Interface'}.<br/>
                <span style="color: #f4b400;">[AI_ASSISTANT]</span> Dispatching coordinates to emergency nodes...<br/>
                <span style="color: #f4b400;">[MESSAGE]</span> "${selectedReport.message}"
              </div>
            </div>

            <div class="footer">
              <div style="flex: 1;">
                <div style="font-size: 10px; font-weight: 700; color: #1a202c; margin-bottom: 5px;">SECURITY AUTHENTICATION</div>
                <div style="font-size: 9px; color: #718096; max-width: 300px;">
                  This report is digitally signed and encrypted. It serves as legal evidence of the incident and location at the time of trigger. Tampering is a federal offense.
                </div>
              </div>
              <div style="text-align: right;">
                <div style="display: flex; gap: 20px; align-items: flex-end;">
                    <div style="text-align: center;">
                        <div style="width: 60px; height: 60px; border: 1px solid #cbd5e0; margin-bottom: 5px; display: flex; align-items: center; justify-content: center; font-size: 40px; color: #e2e8f0;">QR</div>
                        <span style="font-size: 8px; font-weight: 800;">VERIFY SOURCE</span>
                    </div>
                    <div style="text-align: center;">
                        <div style="font-family: 'cursive'; font-size: 24px; border-bottom: 1px solid #1a202c; padding: 0 20px; margin-bottom: 5px;">Trinetra Admin</div>
                        <span style="font-size: 8px; font-weight: 800;">DIGITAL SIGNATURE</span>
                    </div>
                </div>
              </div>
            </div>
          </div>
        </body>
      </html>
    `;

    const blob = new Blob([fullHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `TRINETRA_AUDIT_${selectedReport.id.toString().slice(-6)}.html`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  if (isMobile) {
    return <MobileSOSReports user={loggedInUser} onLogout={() => { localStorage.removeItem("trinetra_user"); window.location.href = "/"; }} />;
  }

  return (
    <div className={`nr-root ${dark ? 'dark' : 'light'}`} style={{ background: 'var(--bg1)', minHeight: '100vh' }}>

      <header className="nr-topbar glass-card" style={{ position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 20px', height: '64px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <button className="topbar-btn" onClick={() => setSidebarOpen(true)}><FaBars size={18} /></button>
          <Logo height={24} />
          <span style={{ fontSize: '12px', fontWeight: 700, color: 'var(--accent)', letterSpacing: '2px', textTransform: 'uppercase', marginLeft: '10px' }}>REPORT CENTER</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <div className="topbar-time" style={{ fontSize: '13px', fontWeight: 600, color: 'var(--text3)' }}>{new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
          <button className="topbar-btn"><FaBell size={16} /></button>
          <div className="sb-avatar" style={{ width: '32px', height: '32px', fontSize: '12px' }}>{loggedInUser.name?.[0] || 'U'}</div>
        </div>
      </header>

      <Sidebar
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        user={loggedInUser}
        onLogout={() => { localStorage.removeItem("trinetra_user"); window.location.href = "/"; }}
      />

      <main style={{ padding: '84px 20px 20px 20px', maxWidth: '1400px', margin: '0 auto' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '380px 1fr', gap: '24px', height: 'calc(100vh - 120px)' }}>

          <aside className="glass-card fade-up" style={{ display: 'flex', flexDirection: 'column', overflow: 'hidden', border: '1px solid var(--border)' }}>
            <div style={{ padding: '24px', borderBottom: '1px solid var(--border)', background: 'rgba(255,255,255,0.02)' }}>
              <h2 style={{ fontSize: '18px', fontWeight: 800, color: 'var(--text)', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
                <FaFileInvoice color="var(--accent)" /> Incident History
              </h2>
            </div>

            <div style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>
              {loading ? (
                [1, 2, 3].map(i => <div key={i} style={{ height: '80px', background: 'var(--bg3)', borderRadius: '16px', marginBottom: '12px', animation: 'pulse 1.5s infinite' }} />)
              ) : reports.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '60px 20px', opacity: 0.5 }}>
                  <FaShieldAlt size={40} style={{ marginBottom: '15px' }} />
                  <p>No records found.</p>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                  {reports.map(r => (
                    <div
                      key={r.id}
                      onClick={() => setSelectedReport(r)}
                      className={`report-card-item ${selectedReport?.id === r.id ? 'active' : ''}`}
                      style={{
                        padding: '16px', borderRadius: '16px', cursor: 'pointer', transition: 'all 0.3s',
                        background: selectedReport?.id === r.id ? 'linear-gradient(135deg, var(--accent), #2b6cb0)' : 'var(--bg2)',
                        border: '1px solid var(--border)', color: selectedReport?.id === r.id ? 'white' : 'var(--text)'
                      }}
                    >
                      <div style={{ fontSize: '10px', fontWeight: 800, opacity: 0.7 }}>ID: {r.id.toString().slice(-6)}</div>
                      <div style={{ fontSize: '15px', fontWeight: 700, marginTop: '4px' }}>{new Date(r.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} SOS</div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '11px', marginTop: '10px', opacity: 0.7 }}>
                        <FaClock size={10} /> {new Date(r.timestamp).toLocaleDateString()}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </aside>

          <section style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {selectedReport ? (
              <div className="glass-card fade-up" style={{ padding: '40px', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <div style={{ width: '100px', height: '100px', background: 'rgba(52,168,83,0.1)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '24px' }}>
                  <FaCheckCircle size={50} color="#34a853" />
                </div>
                <h2 style={{ fontSize: '24px', fontWeight: 800 }}>Audit File Generated</h2>
                <p style={{ color: 'var(--text3)', maxWidth: '400px', margin: '15px 0 30px 0' }}>
                  The official forensic audit for Incident #{selectedReport.id.toString().slice(-6)} is ready for offline collection.
                </p>

                <div style={{ display: 'flex', gap: '15px' }}>
                  <button onClick={handleDownload} className="premium-btn primary" style={{ padding: '18px 40px', fontSize: '16px' }}>
                    <FaDownload /> Download Forensic Audit
                  </button>
                  <button onClick={() => deleteReport(selectedReport.id)} className="premium-btn danger" style={{ padding: '18px 25px' }}>
                    <FaTrash />
                  </button>
                </div>

                <div style={{ marginTop: '40px', padding: '15px 25px', background: 'var(--bg3)', borderRadius: '12px', fontSize: '12px', color: 'var(--text3)', border: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: '10px' }}>
                  <FaShieldAlt color="var(--accent)" />
                  <span>Security HASH: {Math.random().toString(36).substring(7).toUpperCase()} (Verified)</span>
                </div>

                {/* HIDDEN REPORT TEMPLATE (Used for logic but screen-hidden) */}
                <div id="printable-report" style={{ display: 'none' }}>
                  {/* Empty but required by handleDownload logic if we use DOM parsing, 
                            but now we use template literals for better control */}
                </div>
              </div>
            ) : (
              <div className="glass-card" style={{ height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--text3)' }}>
                <FaShieldAlt size={40} style={{ opacity: 0.1, marginBottom: '15px' }} />
                <p>Select an incident from the history.</p>
              </div>
            )}
          </section>
        </div>
      </main>

      <style>{`
        .report-card-item:hover { transform: translateX(5px); background: var(--bg3); }
        .premium-btn { padding: 12px 24px; border-radius: 12px; border: none; cursor: pointer; font-size: 14px; font-weight: 700; display: flex; align-items: center; gap: 10px; transition: all 0.2s; }
        .premium-btn.primary { background: var(--accent); color: white; box-shadow: 0 4px 15px rgba(66,133,244,0.3); }
        .premium-btn.danger { background: rgba(234,67,53,0.1); color: #ea4335; }
        .premium-btn:hover { transform: translateY(-2px); filter: brightness(1.1); }
      `}</style>
    </div>
  );
};

export default SOSReports;
